spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var centerY = H / 2 + 10;
    var padding = 50;
    var maxVal = 15;
    var spacing = (W - padding * 2) / maxVal;

    function getX(val) {
      return padding + val * spacing;
    }

    // Draw Axis
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(padding - 20, centerY);
    ctx.lineTo(W - padding + 20, centerY);
    ctx.stroke();

    // Draw ticks and labels
    for (var i = 0; i <= maxVal; i++) {
      var tx = getX(i);
      var isMultiple = (i > 0 && i % 3 === 0);

      ctx.strokeStyle = isMultiple ? '#10B981' : '#4B5563';
      ctx.lineWidth = isMultiple ? 2.5 : 1.5;
      ctx.beginPath();
      ctx.moveTo(tx, centerY - 6);
      ctx.lineTo(tx, centerY + 6);
      ctx.stroke();

      ctx.fillStyle = isMultiple ? '#34D399' : '#6B7280';
      ctx.font = isMultiple ? 'bold 12px -apple-system, sans-serif' : '10px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText(i.toString(), tx, centerY + 20);
    }

    // Animation phases (8s cycle)
    var duration = 8000;
    var progress = (t % duration) / duration;

    var numJumps = 5;
    var jumpDuration = 0.7 / numJumps; // Jumps take up first 70% of time

    // Draw jumps
    for (var j = 0; j < numJumps; j++) {
      var startJumpT = j * jumpDuration;
      var endJumpT = (j + 1) * jumpDuration;

      if (progress > startJumpT) {
        var jumpProgress = Math.min(1.0, (progress - startJumpT) / jumpDuration);

        var startVal = j * 3;
        var endVal = (j + 1) * 3;
        var startX = getX(startVal);
        var endX = getX(startVal + 3 * jumpProgress);

        ctx.strokeStyle = '#60A5FA';
        ctx.lineWidth = 3.5;
        ctx.beginPath();
        ctx.moveTo(startX, centerY);

        var fullEndX = getX(endVal);
        for (var x = startX; x <= endX; x++) {
          var ratio = (x - startX) / (fullEndX - startX);
          // Parabolic arc
          var arcY = centerY - Math.sin(ratio * Math.PI) * 35;
          ctx.lineTo(x, arcY);
        }
        ctx.stroke();

        // Highlight the landing multiples
        if (progress > endJumpT || jumpProgress >= 1.0) {
          ctx.fillStyle = '#EC4899'; // Coral target dot
          ctx.beginPath();
          ctx.arc(getX(endVal), centerY, 6, 0, Math.PI * 2);
          ctx.fill();
        }
      }
    }

    // Label text
    ctx.fillStyle = '#F3F4F6';
    ctx.font = 'bold 16px -apple-system, sans-serif';
    ctx.textAlign = 'center';

    if (progress > 0.7) {
      ctx.fillText('Multiples of 3: 3, 6, 9, 12, 15', W / 2, centerY - 65);
    } else {
      var currentMultipleIdx = Math.floor(progress / jumpDuration) + 1;
      currentMultipleIdx = Math.min(5, Math.max(1, currentMultipleIdx));
      ctx.fillText('Skip counting: ' + (currentMultipleIdx * 3), W / 2, centerY - 65);
    }
  }
};
